module top_module(
    COUT,
    SUM ,
    A   ,
    B   ,
    CIN 
);output COUT;
    output SUM ;
    input  A   ;
    input  B   ;
    input  CIN ;

    wire carry_and_1, w2, w3;

    // XOR gates for SUM output
    assign SUM = A ^ B ^ CIN;

    // AND gates for COUT output
    assign carry_and_1 = A & B;
    assign w2 = A & CIN;
    assign w3 = B & CIN;
    assign COUT = carry_and_1 | w2 | w3;

endmodule
